schema.input:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "User Data Schema",
  "type": "object",
  "properties": {
    "user_id": {
      "type": "string"
    },
    "video_watched_w_ts": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "id": {
            "type": "string"
          },
          "ts": {
            "type": "string",
            "format": "date-time"
          }
        },
        "required": ["id", "ts"],
        "additionalProperties": false
      }
    },
    "video_aborted_w_ts": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "id": {
            "type": "string"
          },
          "ts": {
            "type": "string",
            "format": "date-time"
          }
        },
        "required": ["id", "ts"],
        "additionalProperties": false
      }
    },
    "video_keep_watching_w_ts": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "id": {
            "type": "string"
          },
          "ts": {
            "type": "string",
            "format": "date-time"
          }
        },
        "required": ["id", "ts"],
        "additionalProperties": false
      }
    },
    "video_historical_fingerprint": {
      "type": "string"
    },
    "reduced_video_historical_fingerprint": {
      "type": "string"
    },
    "lastARESLoaderModified": {
      "type": "string",
      "format": "date-time"
    }
  },
  "required": ["user_id"],
  "additionalProperties": false
}
